// Aggregate all provider model data
// Input: items from all fetch nodes
const allModels = [];
const freeModels = [];
const providerStats = {};

for (const item of $input.all()) {
  const provider = item.json.provider || 'unknown';
  const models = item.json.models || item.json.data || [];

  providerStats[provider] = { total: models.length, free: 0 };

  for (const m of models) {
    const promptPrice = parseFloat(m.pricing?.prompt || m.prompt_price || '0');
    const completionPrice = parseFloat(m.pricing?.completion || m.completion_price || '0');
    const isFree = promptPrice === 0 && completionPrice === 0;
    const ctx = m.context_length || m.inputTokenLimit || 0;

    allModels.push({
      provider,
      model_id: m.id || m.model_id,
      name: (m.id || m.model_id).split('/').pop(),
      context_length: ctx,
      is_free: isFree,
      prompt_price: promptPrice,
      completion_price: completionPrice,
      tier: classifyTier(m.id || m.model_id, ctx, isFree),
      role: classifyRole(m.id || m.model_id, ctx),
    });

    if (isFree) {
      freeModels.push(allModels[allModels.length - 1]);
      providerStats[provider].free++;
    }
  }
}

function classifyTier(name, ctx, isFree) {
  const n = name.toLowerCase();
  if (['opus','o1','o3','405b','70b','ultra','2.5-pro'].some(s => n.includes(s)) && ctx >= 32768) return 'T1-ULTRA';
  if (name.includes('ollama')) return 'T4-LOCAL';
  if (isFree) return 'T3-FREE';
  return 'T2-FAST';
}

function classifyRole(name, ctx) {
  const n = name.toLowerCase();
  if (['o1','o3','opus','2.5-pro','405b','70b'].some(s => n.includes(s))) return 'reasoning';
  if (['flash','8b','turbo','instant','lite'].some(s => n.includes(s))) return 'utility';
  if (['embed','nomic','bge','e5'].some(s => n.includes(s))) return 'embedding';
  if (ctx >= 100000) return 'long-context';
  return 'general';
}

// Missed opportunities: free models not in current config
const configured = new Set([
  'openrouter/openrouter/owl-alpha',
  'nvidia_nim/nemotron-3-ultra',
  'gemini/gemini-2.5-pro',
  'gemini/gemini-2.5-flash',
  'openai/qwen3.5-plus',
  'groq/llama-3.3-70b-versatile',
  'groq/llama-3.1-8b-instant',
  'openrouter/google/gemini-2.5-flash:free',
  'ollama/deepseek-r1:8b',
  'ollama/dolphin3',
  'ollama/nomic-embed-text',
]);

const missed = freeModels
  .filter(m => !configured.has(m.model_id))
  .sort((a, b) => b.context_length - a.context_length);

return [{
  json: {
    generated_at: new Date().toISOString(),
    total_models: allModels.length,
    free_models: freeModels.length,
    missed_opportunities: missed.length,
    provider_stats: providerStats,
    missed_top_20: missed.slice(0, 20),
    free_by_tier: {
      'T1-ULTRA': freeModels.filter(m => m.tier === 'T1-ULTRA').map(m => m.model_id),
      'T3-FREE': freeModels.filter(m => m.tier === 'T3-FREE').map(m => m.model_id),
    }
  }
}];

// Generate Markdown report
const data = $input.first().json;
const now = new Date().toISOString().slice(0, 10);

let md = `# Model Intelligence Report - ${now}\n\n`;
md += `**Generated:** ${data.generated_at}\n`;
md += `**Total Models:** ${data.total_models}\n`;
md += `**Free Models:** ${data.free_models}\n`;
md += `**Missed Opportunities:** ${data.missed_opportunities}\n\n`;

md += `## Provider Stats\n\n`;
md += `| Provider | Total | Free |\n|----------|-------|------|\n`;
for (const [prov, stats] of Object.entries(data.provider_stats)) {
  md += `| ${prov} | ${stats.total} | ${stats.free} |\n`;
}

md += `\n## Top Missed Free Models (not in config.yml)\n\n`;
md += `| Model | Context | Tier | Role |\n|-------|---------|------|------|\n`;
for (const m of data.missed_top_20) {
  const ctx = m.context_length ? m.context_length.toLocaleString() : '?';
  md += `| \`${m.model_id}\` | ${ctx} | ${m.tier} | ${m.role} |\n`;
}

return [{ json: { report: md, filename: `model_intelligence_${now}.md` } }];

// Generate alert if significant missed opportunities found
const data = $input.first().json;
const missed = data.missed_top_20 || [];

if (missed.length > 0) {
  const topFree = missed.slice(0, 5).map(m => 
    `• \`${m.model_id}\` (ctx=${m.context_length?.toLocaleString() || '?'}, ${m.role})`
  ).join('\n');

  return [{
    json: {
      message: `🧠 Model Intelligence Alert\n\nFound ${data.missed_opportunities} free models not in your LiteLLM config.\n\nTop picks:\n${topFree}\n\nSee full report in: /mnt/d/docker/compose/ai/litellm/config/intelligence_reports/`,
      hasAlert: true
    }
  }];
}

return [{ json: { message: '✅ No new free models found. All known free models are already configured.', hasAlert: false } }];
